    inline bool get_CH13_CTRL_TRIG_AHB_ERROR() volatile
    {
        return CH13_CTRL_TRIG & (1u << 31u);
    }

    /**
     * Get all of CH13_CTRL_TRIG's bit fields.
     *
     * (read-write) DMA Channel 13 Control and Status
     */
    inline void get_CH13_CTRL_TRIG(
        bool &EN, bool &HIGH_PRIORITY, DMA_CH13_CTRL_TRIG_DATA_SIZE &DATA_SIZE,
        bool &INCR_READ, bool &INCR_READ_REV, bool &INCR_WRITE,
        bool &INCR_WRITE_REV, DMA_CH13_CTRL_TRIG_RING_SIZE &RING_SIZE,
        bool &RING_SEL, uint8_t &CHAIN_TO,
        DMA_CH13_CTRL_TRIG_TREQ_SEL &TREQ_SEL, bool &IRQ_QUIET, bool &BSWAP,
        bool &SNIFF_EN, bool &BUSY, bool &WRITE_ERROR, bool &READ_ERROR,
        bool &AHB_ERROR) volatile
    {
        uint32_t curr = CH13_CTRL_TRIG;

        EN = curr & 1u;
        HIGH_PRIORITY = curr & (1u << 1u);
        DATA_SIZE = DMA_CH13_CTRL_TRIG_DATA_SIZE((curr >> 2u) & 0b11u);
        INCR_READ = curr & (1u << 4u);
        INCR_READ_REV = curr & (1u << 5u);
        INCR_WRITE = curr & (1u << 6u);
        INCR_WRITE_REV = curr & (1u << 7u);
        RING_SIZE = DMA_CH13_CTRL_TRIG_RING_SIZE((curr >> 8u) & 0xfu);
        RING_SEL = curr & (1u << 12u);
        CHAIN_TO = (curr >> 13u) & 0xfu;
        TREQ_SEL = DMA_CH13_CTRL_TRIG_TREQ_SEL((curr >> 17u) & 0b111111u);
        IRQ_QUIET = curr & (1u << 23u);
        BSWAP = curr & (1u << 24u);
        SNIFF_EN = curr & (1u << 25u);
        BUSY = curr & (1u << 26u);
        WRITE_ERROR = curr & (1u << 29u);
        READ_ERROR = curr & (1u << 30u);
        AHB_ERROR = curr & (1u << 31u);
    }

    /**
     * Set all of CH13_CTRL_TRIG's bit fields.
     *
     * (read-write) DMA Channel 13 Control and Status
     */
    inline void set_CH13_CTRL_TRIG(bool EN, bool HIGH_PRIORITY,
                                   DMA_CH13_CTRL_TRIG_DATA_SIZE DATA_SIZE,
                                   bool INCR_READ, bool INCR_READ_REV,
                                   bool INCR_WRITE, bool INCR_WRITE_REV,
                                   DMA_CH13_CTRL_TRIG_RING_SIZE RING_SIZE,
                                   bool RING_SEL, uint8_t CHAIN_TO,
                                   DMA_CH13_CTRL_TRIG_TREQ_SEL TREQ_SEL,
                                   bool IRQ_QUIET, bool BSWAP, bool SNIFF_EN,
                                   bool WRITE_ERROR, bool READ_ERROR) volatile
    {
        uint32_t curr = CH13_CTRL_TRIG;

        curr &= ~(0b1u);
        curr |= (EN & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (HIGH_PRIORITY & 0b1u) << 1u;
        curr &= ~(0b11u << 2u);
        curr |= (std::to_underlying(DATA_SIZE) & 0b11u) << 2u;
        curr &= ~(0b1u << 4u);
        curr |= (INCR_READ & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (INCR_READ_REV & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (INCR_WRITE & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (INCR_WRITE_REV & 0b1u) << 7u;
        curr &= ~(0xfu << 8u);
        curr |= (std::to_underlying(RING_SIZE) & 0xfu) << 8u;
        curr &= ~(0b1u << 12u);
        curr |= (RING_SEL & 0b1u) << 12u;
        curr &= ~(0xfu << 13u);
        curr |= (CHAIN_TO & 0xfu) << 13u;
        curr &= ~(0b111111u << 17u);
        curr |= (std::to_underlying(TREQ_SEL) & 0b111111u) << 17u;
        curr &= ~(0b1u << 23u);
        curr |= (IRQ_QUIET & 0b1u) << 23u;
        curr &= ~(0b1u << 24u);
        curr |= (BSWAP & 0b1u) << 24u;
        curr &= ~(0b1u << 25u);
        curr |= (SNIFF_EN & 0b1u) << 25u;
        curr &= ~(0b1u << 29u);
        curr |= (WRITE_ERROR & 0b1u) << 29u;
        curr &= ~(0b1u << 30u);
        curr |= (READ_ERROR & 0b1u) << 30u;

        CH13_CTRL_TRIG = curr;
    }

    /**
     * Get CH14_TRANS_COUNT's COUNT field.
     *
     * 28-bit transfer count (256 million transfers maximum).
     *
     *                             Program the number of bus transfers a
     * channel will perform before halting. Note that, if transfers are larger
     * than one byte in size, this is not equal to the number of bytes
     * transferred (see CTRL_DATA_SIZE).
     *
     *                             When the channel is active, reading this
     * register shows the number of transfers remaining, updating automatically
     * each time a write transfer completes.
     *
     *                             Writing this register sets the RELOAD value
     * for the transfer counter. Each time this channel is triggered, the
     * RELOAD value is copied into the live transfer counter. The channel can
     * be started multiple times, and will perform the same number of transfers
     * each time, as programmed by most recent write.
     *
     *                             The RELOAD value can be observed at
     * CHx_DBG_TCR. If TRANS_COUNT is used as a trigger, the written value is
     * used immediately as the length of the new transfer sequence, as well as
     * being written to RELOAD.
     */
    inline uint32_t get_CH14_TRANS_COUNT_COUNT() volatile
    {
        return CH14_TRANS_COUNT & 0xfffffffu;
    }

    /**
     * Set CH14_TRANS_COUNT's COUNT field.
     *
     * 28-bit transfer count (256 million transfers maximum).
     *
     *                             Program the number of bus transfers a
     * channel will perform before halting. Note that, if transfers are larger
     * than one byte in size, this is not equal to the number of bytes
     * transferred (see CTRL_DATA_SIZE).
     *
     *                             When the channel is active, reading this
     * register shows the number of transfers remaining, updating automatically
     * each time a write transfer completes.
     *
     *                             Writing this register sets the RELOAD value
     * for the transfer counter. Each time this channel is triggered, the
     * RELOAD value is copied into the live transfer counter. The channel can
     * be started multiple times, and will perform the same number of transfers
     * each time, as programmed by most recent write.
     *
     *                             The RELOAD value can be observed at
     * CHx_DBG_TCR. If TRANS_COUNT is used as a trigger, the written value is
     * used immediately as the length of the new transfer sequence, as well as
     * being written to RELOAD.
     */
    inline void set_CH14_TRANS_COUNT_COUNT(uint32_t value) volatile
    {
        uint32_t curr = CH14_TRANS_COUNT;

        curr &= ~(0xfffffffu);
        curr |= (value & 0xfffffffu);

        CH14_TRANS_COUNT = curr;
    }

    /**
     * Get CH14_TRANS_COUNT's MODE field.
     *
     * When MODE is 0x0, the transfer count decrements with each transfer until
     * 0, and then the channel triggers the next channel indicated by
     * CTRL_CHAIN_TO.
     *
     *                             When MODE is 0x1, the transfer count
     * decrements with each transfer until 0, and then the channel re-triggers
     * itself, in addition to the trigger indicated by CTRL_CHAIN_TO. This is
     * useful for e.g. an endless ring-buffer DMA with periodic interrupts.
     *
     *                             When MODE is 0xf, the transfer count does
     * not decrement. The DMA channel performs an endless sequence of
     * transfers, never triggering other channels or raising interrupts, until
     * an ABORT is raised.
     *
     *                             All other values are reserved.
     */
    inline DMA_CH14_TRANS_COUNT_MODE get_CH14_TRANS_COUNT_MODE() volatile
    {
        return DMA_CH14_TRANS_COUNT_MODE((CH14_TRANS_COUNT >> 28u) & 0xfu);
    }

    /**
     * Set CH14_TRANS_COUNT's MODE field.
     *
     * When MODE is 0x0, the transfer count decrements with each transfer until
     * 0, and then the channel triggers the next channel indicated by
     * CTRL_CHAIN_TO.
     *
     *                             When MODE is 0x1, the transfer count
     * decrements with each transfer until 0, and then the channel re-triggers
     * itself, in addition to the trigger indicated by CTRL_CHAIN_TO. This is
     * useful for e.g. an endless ring-buffer DMA with periodic interrupts.
     *
     *                             When MODE is 0xf, the transfer count does
     * not decrement. The DMA channel performs an endless sequence of
     * transfers, never triggering other channels or raising interrupts, until
     * an ABORT is raised.
     *
     *                             All other values are reserved.
     */
    inline void set_CH14_TRANS_COUNT_MODE(
        DMA_CH14_TRANS_COUNT_MODE value) volatile
    {
        uint32_t curr = CH14_TRANS_COUNT;

        curr &= ~(0xfu << 28u);
        curr |= (std::to_underlying(value) & 0xfu) << 28u;

        CH14_TRANS_COUNT = curr;
    }

    /**
     * Get all of CH14_TRANS_COUNT's bit fields.
     *
     * (read-write) DMA Channel 14 Transfer Count
     */
    inline void get_CH14_TRANS_COUNT(uint32_t &COUNT,
                                     DMA_CH14_TRANS_COUNT_MODE &MODE) volatile
    {
        uint32_t curr = CH14_TRANS_COUNT;

        COUNT = curr & 0xfffffffu;
        MODE = DMA_CH14_TRANS_COUNT_MODE((curr >> 28u) & 0xfu);
    }

    /**
     * Set all of CH14_TRANS_COUNT's bit fields.
     *
     * (read-write) DMA Channel 14 Transfer Count
     */
    inline void set_CH14_TRANS_COUNT(uint32_t COUNT,
                                     DMA_CH14_TRANS_COUNT_MODE MODE) volatile
    {
        uint32_t curr = CH14_TRANS_COUNT;

        curr &= ~(0xfffffffu);
        curr |= (COUNT & 0xfffffffu);
        curr &= ~(0xfu << 28u);
        curr |= (std::to_underlying(MODE) & 0xfu) << 28u;

        CH14_TRANS_COUNT = curr;
    }

