    /**
     * Get all of CH15_CTRL_TRIG's bit fields.
     *
     * (read-write) DMA Channel 15 Control and Status
     */
    inline void get_CH15_CTRL_TRIG(
        bool &EN, bool &HIGH_PRIORITY, DMA_CH15_CTRL_TRIG_DATA_SIZE &DATA_SIZE,
        bool &INCR_READ, bool &INCR_READ_REV, bool &INCR_WRITE,
        bool &INCR_WRITE_REV, DMA_CH15_CTRL_TRIG_RING_SIZE &RING_SIZE,
        bool &RING_SEL, uint8_t &CHAIN_TO,
        DMA_CH15_CTRL_TRIG_TREQ_SEL &TREQ_SEL, bool &IRQ_QUIET, bool &BSWAP,
        bool &SNIFF_EN, bool &BUSY, bool &WRITE_ERROR, bool &READ_ERROR,
        bool &AHB_ERROR) volatile
    {
        uint32_t curr = CH15_CTRL_TRIG;

        EN = curr & 1u;
        HIGH_PRIORITY = curr & (1u << 1u);
        DATA_SIZE = DMA_CH15_CTRL_TRIG_DATA_SIZE((curr >> 2u) & 0b11u);
        INCR_READ = curr & (1u << 4u);
        INCR_READ_REV = curr & (1u << 5u);
        INCR_WRITE = curr & (1u << 6u);
        INCR_WRITE_REV = curr & (1u << 7u);
        RING_SIZE = DMA_CH15_CTRL_TRIG_RING_SIZE((curr >> 8u) & 0xfu);
        RING_SEL = curr & (1u << 12u);
        CHAIN_TO = (curr >> 13u) & 0xfu;
        TREQ_SEL = DMA_CH15_CTRL_TRIG_TREQ_SEL((curr >> 17u) & 0b111111u);
        IRQ_QUIET = curr & (1u << 23u);
        BSWAP = curr & (1u << 24u);
        SNIFF_EN = curr & (1u << 25u);
        BUSY = curr & (1u << 26u);
        WRITE_ERROR = curr & (1u << 29u);
        READ_ERROR = curr & (1u << 30u);
        AHB_ERROR = curr & (1u << 31u);
    }

    /**
     * Set all of CH15_CTRL_TRIG's bit fields.
     *
     * (read-write) DMA Channel 15 Control and Status
     */
    inline void set_CH15_CTRL_TRIG(bool EN, bool HIGH_PRIORITY,
                                   DMA_CH15_CTRL_TRIG_DATA_SIZE DATA_SIZE,
                                   bool INCR_READ, bool INCR_READ_REV,
                                   bool INCR_WRITE, bool INCR_WRITE_REV,
                                   DMA_CH15_CTRL_TRIG_RING_SIZE RING_SIZE,
                                   bool RING_SEL, uint8_t CHAIN_TO,
                                   DMA_CH15_CTRL_TRIG_TREQ_SEL TREQ_SEL,
                                   bool IRQ_QUIET, bool BSWAP, bool SNIFF_EN,
                                   bool WRITE_ERROR, bool READ_ERROR) volatile
    {
        uint32_t curr = CH15_CTRL_TRIG;

        curr &= ~(0b1u);
        curr |= (EN & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (HIGH_PRIORITY & 0b1u) << 1u;
        curr &= ~(0b11u << 2u);
        curr |= (std::to_underlying(DATA_SIZE) & 0b11u) << 2u;
        curr &= ~(0b1u << 4u);
        curr |= (INCR_READ & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (INCR_READ_REV & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (INCR_WRITE & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (INCR_WRITE_REV & 0b1u) << 7u;
        curr &= ~(0xfu << 8u);
        curr |= (std::to_underlying(RING_SIZE) & 0xfu) << 8u;
        curr &= ~(0b1u << 12u);
        curr |= (RING_SEL & 0b1u) << 12u;
        curr &= ~(0xfu << 13u);
        curr |= (CHAIN_TO & 0xfu) << 13u;
        curr &= ~(0b111111u << 17u);
        curr |= (std::to_underlying(TREQ_SEL) & 0b111111u) << 17u;
        curr &= ~(0b1u << 23u);
        curr |= (IRQ_QUIET & 0b1u) << 23u;
        curr &= ~(0b1u << 24u);
        curr |= (BSWAP & 0b1u) << 24u;
        curr &= ~(0b1u << 25u);
        curr |= (SNIFF_EN & 0b1u) << 25u;
        curr &= ~(0b1u << 29u);
        curr |= (WRITE_ERROR & 0b1u) << 29u;
        curr &= ~(0b1u << 30u);
        curr |= (READ_ERROR & 0b1u) << 30u;

        CH15_CTRL_TRIG = curr;
    }

